    override fun read(buf: ByteBuffer): StoreBridge {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: StoreBridge) = 8UL

    override fun write(value: StoreBridge, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



