sealed class TmslException(message: String): kotlin.Exception(message) {
        
        class Io(message: String) : TmslException(message)
        
        class InvalidMagic(message: String) : TmslException(message)
        
        class InvalidVersion(message: String) : TmslException(message)
        
        class MmapException(message: String) : TmslException(message)
        
        class CompressionException(message: String) : TmslException(message)
        
        class DecompressionException(message: String) : TmslException(message)
        
        class InvalidData(message: String) : TmslException(message)
        
        class NotFound(message: String) : TmslException(message)
        
        class Expired(message: String) : TmslException(message)
        
        class AlreadyExists(message: String) : TmslException(message)
        
        class SegmentFull(message: String) : TmslException(message)
        
        class QueueAlreadyOpen(message: String) : TmslException(message)
        
        class QueueNotOpen(message: String) : TmslException(message)
        
        class ConsumerGroupNotFound(message: String) : TmslException(message)
        
        class ConsumerGroupExists(message: String) : TmslException(message)
        
        class QueueClosed(message: String) : TmslException(message)
        
        class PendingFull(message: String) : TmslException(message)
        
        class StoreClosed(message: String) : TmslException(message)
        
        class DatasetClosed(message: String) : TmslException(message)
        
        class QueueBridgeClosed(message: String) : TmslException(message)
        
        class IteratorExhausted(message: String) : TmslException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<TmslException> {
        override fun lift(error_buf: RustBuffer.ByValue): TmslException = FfiConverterTypeTmslError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeTmslError : FfiConverterRustBuffer<TmslException> {
    override fun read(buf: ByteBuffer): TmslException {
        
            return when(buf.getInt()) {
            1 -> TmslException.Io(FfiConverterString.read(buf))
            2 -> TmslException.InvalidMagic(FfiConverterString.read(buf))
            3 -> TmslException.InvalidVersion(FfiConverterString.read(buf))
            4 -> TmslException.MmapException(FfiConverterString.read(buf))
            5 -> TmslException.CompressionException(FfiConverterString.read(buf))
            6 -> TmslException.DecompressionException(FfiConverterString.read(buf))
            7 -> TmslException.InvalidData(FfiConverterString.read(buf))
            8 -> TmslException.NotFound(FfiConverterString.read(buf))
            9 -> TmslException.Expired(FfiConverterString.read(buf))
            10 -> TmslException.AlreadyExists(FfiConverterString.read(buf))
            11 -> TmslException.SegmentFull(FfiConverterString.read(buf))
            12 -> TmslException.QueueAlreadyOpen(FfiConverterString.read(buf))
            13 -> TmslException.QueueNotOpen(FfiConverterString.read(buf))
            14 -> TmslException.ConsumerGroupNotFound(FfiConverterString.read(buf))
            15 -> TmslException.ConsumerGroupExists(FfiConverterString.read(buf))
            16 -> TmslException.QueueClosed(FfiConverterString.read(buf))
            17 -> TmslException.PendingFull(FfiConverterString.read(buf))
            18 -> TmslException.StoreClosed(FfiConverterString.read(buf))
            19 -> TmslException.DatasetClosed(FfiConverterString.read(buf))
            20 -> TmslException.QueueBridgeClosed(FfiConverterString.read(buf))
            21 -> TmslException.IteratorExhausted(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: TmslException): ULong {
        return 4UL
    }

    override fun write(value: TmslException, buf: ByteBuffer) {
        when(value) {
            is TmslException.Io -> {
                buf.putInt(1)
                Unit
            }
            is TmslException.InvalidMagic -> {
                buf.putInt(2)
                Unit
            }
            is TmslException.InvalidVersion -> {
                buf.putInt(3)
                Unit
            }
            is TmslException.MmapException -> {
                buf.putInt(4)
                Unit
            }
            is TmslException.CompressionException -> {
                buf.putInt(5)
                Unit
            }
            is TmslException.DecompressionException -> {
                buf.putInt(6)
                Unit
            }
            is TmslException.InvalidData -> {
                buf.putInt(7)
                Unit
            }
            is TmslException.NotFound -> {
                buf.putInt(8)
                Unit
            }
            is TmslException.Expired -> {
                buf.putInt(9)
                Unit
            }
            is TmslException.AlreadyExists -> {
                buf.putInt(10)
                Unit
            }
            is TmslException.SegmentFull -> {
